{"l": 43, "sit": "Sag, dass es gleich zu regnen scheint (Verb-Anschein, そう).", "more": [{"sit": "Sag, dass der Knopf gleich abzufallen scheint.", "jp": "ボタンが <ruby>取<rt>と</rt></ruby>れそうです。", "de": "Der Knopf scheint gleich abzufallen."}, {"sit": "Sag, dass die Tasche gleich zu zerreißen scheint.", "jp": "かばんが <ruby>壊<rt>こわ</rt></ruby>れそうです。", "de": "Die Tasche scheint gleich kaputtzugehen."}]},
{"l": 43, "sit": "Sag, dass du kurz zum Konbini gehst und eine Bento mitbringst (て来ます).", "more": [{"sit": "Sag, dass du kurz zur Bank gehst und gleich zurückkommst.", "jp": "<ruby>銀行<rt>ぎんこう</rt></ruby>へ <ruby>行<rt>い</rt></ruby>って <ruby>来<rt>き</rt></ruby>ます。", "de": "Ich gehe kurz zur Bank und komme zurück."}, {"sit": "Sag, dass es langsam kalt wird.", "jp": "<ruby>寒<rt>さむ</rt></ruby>く なって <ruby>来<rt>き</rt></ruby>ました。", "de": "Es wird langsam kalt."}]},
{"l": 43, "sit": "Sag, dass es nicht so aussieht, als würdest du heute fertig (そうにない).", "more": [{"sit": "Sag, dass es nicht aussieht, als würde es heute regnen.", "jp": "<ruby>今日<rt>きょう</rt></ruby>は <ruby>雨<rt>あめ</rt></ruby>が <ruby>降<rt>ふ</rt></ruby>りそうに ありません。", "de": "Es sieht nicht nach Regen aus heute."}, {"sit": "Sag, dass es nicht aussieht, als würde der Bus bald kommen.", "jp": "バスは すぐ <ruby>来<rt>き</rt></ruby>そうに ありません。", "de": "Der Bus scheint nicht bald zu kommen."}]},
{"l": 44, "sit": "Sag, dass du gestern zu viel Bier getrunken hast (すぎます).", "more": [{"sit": "Sag, dass du gestern zu viel gegessen hast.", "jp": "<ruby>昨日<rt>きのう</rt></ruby> <ruby>食<rt>た</rt></ruby>べすぎました。", "de": "Gestern habe ich zu viel gegessen."}, {"sit": "Sag, dass dieses Zimmer zu klein ist.", "jp": "この <ruby>部屋<rt>へや</rt></ruby>は <ruby>狭<rt>せま</rt></ruby>すぎます。", "de": "Dieses Zimmer ist zu klein."}]},
{"l": 44, "sit": "Sag, dass sich dieser Stift leicht schreibt (やすい).", "more": [{"sit": "Sag, dass dieses Buch leicht zu lesen ist.", "jp": "この <ruby>本<rt>ほん</rt></ruby>は <ruby>読<rt>よ</rt></ruby>みやすいです。", "de": "Dieses Buch ist leicht zu lesen."}, {"sit": "Sag, dass dieser Name schwer auszusprechen ist.", "jp": "この <ruby>名前<rt>なまえ</rt></ruby>は <ruby>言<rt>い</rt></ruby>いにくいです。", "de": "Dieser Name ist schwer auszusprechen."}]},
{"l": 44, "sit": "Bitte jemanden, den Ton lauter zu machen (くします).", "more": [{"sit": "Bitte jemanden, das Zimmer sauber zu machen.", "jp": "<ruby>部屋<rt>へや</rt></ruby>を きれいに して ください。", "de": "Bitte mach das Zimmer sauber."}, {"sit": "Bitte jemanden, den Kaffee süßer zu machen.", "jp": "コーヒーを <ruby>甘<rt>あま</rt></ruby>く して ください。", "de": "Bitte mach den Kaffee süßer."}]},
{"l": 44, "sit": "Im Café: Sag, dass du einen Kaffee nimmst (にします, wählen).", "more": [{"sit": "Im Restaurant: Sag, dass du das Set-Menü nimmst.", "jp": "<ruby>私<rt>わたし</rt></ruby>は <ruby>定食<rt>ていしょく</rt></ruby>に します。", "de": "Ich nehme das Set-Menü."}, {"sit": "Sag, dass du dieses Zimmer (von beiden) nimmst.", "jp": "この <ruby>部屋<rt>へや</rt></ruby>に します。", "de": "Ich nehme dieses Zimmer."}]},
{"l": 44, "sit": "Bitte jemanden, etwas größer zu schreiben (adverbial, く+V).", "more": [{"sit": "Bitte jemanden, langsam zu sprechen (adverbial).", "jp": "ゆっくり <ruby>話<rt>はな</rt></ruby>して ください。", "de": "Bitte sprich langsam."}, {"sit": "Bitte jemanden, schön ordentlich zu schreiben.", "jp": "きれいに <ruby>書<rt>か</rt></ruby>いて ください。", "de": "Bitte schreib ordentlich."}]},
{"l": 45, "sit": "Formell: Sag, dass man sich melden soll, falls man sich verspätet (場合は).", "more": [{"sit": "Formell: Sag, dass man im Notfall diesen Knopf drücken soll.", "jp": "<ruby>危<rt>あぶ</rt></ruby>ない <ruby>場合<rt>ばあい</rt></ruby>は、この ボタンを <ruby>押<rt>お</rt></ruby>して ください。", "de": "Im Notfall drücken Sie diesen Knopf."}, {"sit": "Formell: Sag, dass man bei Fragen anrufen soll.", "jp": "<ruby>分<rt>わ</rt></ruby>からない <ruby>場合<rt>ばあい</rt></ruby>は、<ruby>電話<rt>でんわ</rt></ruby>して ください。", "de": "Bei Unklarheiten rufen Sie an."}]},
{"l": 45, "sit": "Sag enttäuscht: Obwohl du jeden Tag lernst, wirst du nicht besser (のに).", "more": [{"sit": "Sag enttäuscht: Obwohl es teuer war, ging es schnell kaputt.", "jp": "<ruby>高<rt>たか</rt></ruby>かったのに、すぐ <ruby>壊<rt>こわ</rt></ruby>れました。", "de": "Obwohl teuer, ging es schnell kaputt."}, {"sit": "Sag erstaunt: Obwohl Sonntag ist, arbeitet er.", "jp": "<ruby>日曜日<rt>にちようび</rt></ruby>なのに、<ruby>働<rt>はたら</rt></ruby>いて います。", "de": "Obwohl Sonntag ist, arbeitet er."}]},
{"l": 45, "sit": "Sag: Eigentlich sollte die Besprechung um 2 anfangen, wurde aber verschoben (はずでした).", "more": [{"sit": "Sag: Eigentlich sollte er kommen, aber er kam nicht.", "jp": "<ruby>来<rt>く</rt></ruby>る はずでしたが、<ruby>来<rt>き</rt></ruby>ませんでした。", "de": "Er sollte eigentlich kommen, kam aber nicht."}, {"sit": "Sag: Eigentlich sollte es fertig sein, aber es ist noch nicht.", "jp": "<ruby>終<rt>お</rt></ruby>わる はずでしたが、まだです。", "de": "Es sollte fertig sein, ist es aber nicht."}]},
{"l": 46, "sit": "Sag, dass du gerade gleich essen wirst (kurz davor, ところです).", "more": [{"sit": "Sag, dass du gerade nach Hause gehen wolltest.", "jp": "<ruby>今<rt>いま</rt></ruby> <ruby>帰<rt>かえ</rt></ruby>る ところです。", "de": "Ich wollte gerade gehen."}, {"sit": "Sag, dass du gerade fertig geworden bist.", "jp": "<ruby>今<rt>いま</rt></ruby> <ruby>終<rt>お</rt></ruby>わった ところです。", "de": "Ich bin gerade fertig geworden."}]},
{"l": 46, "sit": "Sag, dass du gerade erst nach Japan gekommen bist (たばかり).", "more": [{"sit": "Sag, dass du diese App gerade erst installiert hast.", "jp": "この アプリを <ruby>入<rt>い</rt></ruby>れた ばかりです。", "de": "Ich habe die App gerade erst installiert."}, {"sit": "Sag, dass du gerade erst angefangen hast zu lernen.", "jp": "<ruby>勉強<rt>べんきょう</rt></ruby>を <ruby>始<rt>はじ</rt></ruby>めた ばかりです。", "de": "Ich habe gerade erst zu lernen begonnen."}]},
{"l": 46, "sit": "Schlussfolgere: Frau Tanaka müsste zur Besprechung kommen (はずです).", "more": [{"sit": "Schlussfolgere: Der Laden müsste jetzt offen sein.", "jp": "<ruby>店<rt>みせ</rt></ruby>は もう <ruby>開<rt>あ</rt></ruby>いて いる はずです。", "de": "Der Laden müsste jetzt offen sein."}, {"sit": "Schlussfolgere: Herr Miller müsste das wissen.", "jp": "ミラーさんは <ruby>知<rt>し</rt></ruby>って いる はずです。", "de": "Herr Miller müsste das wissen."}]},
{"l": 47, "sit": "Gib weiter: Laut Wetterbericht soll es morgen regnen (Hörensagen, そう).", "more": [{"sit": "Gib weiter: Es heißt, Herr Miller heiratet bald.", "jp": "ミラーさんは けっこんする そうです。", "de": "Es heißt, Herr Miller heiratet."}, {"sit": "Gib weiter: Laut Nachrichten war ein Erdbeben.", "jp": "ニュースに よると、<ruby>地震<rt>じしん</rt></ruby>が あった そうです。", "de": "Laut Nachrichten gab es ein Erdbeben."}]},
{"l": 47, "sit": "Schlussfolgere aus Indizien: Es scheint draußen zu regnen (ようです).", "more": [{"sit": "Schlussfolgere aus Indizien: Herr Miller scheint nicht da zu sein.", "jp": "ミラーさんは いない ようです。", "de": "Herr Miller scheint nicht da zu sein."}, {"sit": "Schlussfolgere: Es scheint, als wäre der Laden geschlossen.", "jp": "<ruby>店<rt>みせ</rt></ruby>は <ruby>閉<rt>し</rt></ruby>まって いる ようです。", "de": "Der Laden scheint geschlossen zu sein."}]},
{"l": 47, "sit": "Beschreibe deine Wahrnehmung: Draußen hört man Kinderstimmen (がします).", "more": [{"sit": "Beschreibe: Es riecht hier nach Kaffee.", "jp": "コーヒーの においが します。", "de": "Es riecht nach Kaffee."}, {"sit": "Beschreibe: Diese Suppe schmeckt nach Fisch.", "jp": "この スープは <ruby>魚<rt>さかな</rt></ruby>の <ruby>味<rt>あじ</rt></ruby>が します。", "de": "Die Suppe schmeckt nach Fisch."}]},
{"l": 48, "sit": "Sag, dass die Mutter das Kind Gemüse essen ließ (Kausativ).", "more": [{"sit": "Sag, dass der Lehrer die Schüler ein Buch lesen ließ.", "jp": "<ruby>先生<rt>せんせい</rt></ruby>は <ruby>学生<rt>がくせい</rt></ruby>に <ruby>本<rt>ほん</rt></ruby>を <ruby>読<rt>よ</rt></ruby>ませました。", "de": "Der Lehrer ließ die Schüler ein Buch lesen."}, {"sit": "Sag, dass der Chef den Angestellten Überstunden machen ließ.", "jp": "<ruby>部長<rt>ぶちょう</rt></ruby>は <ruby>社員<rt>しゃいん</rt></ruby>に <ruby>残業<rt>ざんぎょう</rt></ruby>させました。", "de": "Der Chef ließ den Mitarbeiter Überstunden machen."}]},
{"l": 48, "sit": "Sag, dass der Vater das Kind spielen ließ (intransitiv, を).", "more": [{"sit": "Sag, dass die Mutter das Kind (zur Schule) gehen ließ (に, Erlaubnis).", "jp": "<ruby>母<rt>はは</rt></ruby>は <ruby>子供<rt>こども</rt></ruby>に <ruby>外<rt>そと</rt></ruby>で <ruby>遊<rt>あそ</rt></ruby>ばせました。", "de": "Die Mutter ließ das Kind draußen spielen."}, {"sit": "Sag, dass der Lehrer den Schüler (zwingend) stehen ließ.", "jp": "<ruby>先生<rt>せんせい</rt></ruby>は <ruby>学生<rt>がくせい</rt></ruby>を <ruby>立<rt>た</rt></ruby>たせました。", "de": "Der Lehrer ließ den Schüler aufstehen."}]},
{"l": 48, "sit": "Dir geht's nicht gut — bitte deinen Chef, dich früher gehen zu lassen (させてください).", "more": [{"sit": "Bitte deinen Chef, dich diese Arbeit machen zu lassen.", "jp": "その <ruby>仕事<rt>しごと</rt></ruby>を <ruby>私<rt>わたし</rt></ruby>に させて ください。", "de": "Lassen Sie mich diese Arbeit machen."}, {"sit": "Bitte höflich, kurz dein Telefon benutzen zu dürfen.", "jp": "<ruby>電話<rt>でんわ</rt></ruby>を <ruby>使<rt>つか</rt></ruby>わせて ください。", "de": "Lassen Sie mich kurz das Telefon benutzen."}]},
{"l": 49, "sit": "Sprich respektvoll über den Chef: Er fährt heute nach Osaka (尊敬語).", "more": [{"sit": "Sprich respektvoll: Hat der Chef die Zeitung schon gelesen?", "jp": "<ruby>社長<rt>しゃちょう</rt></ruby>は もう <ruby>新聞<rt>しんぶん</rt></ruby>を お<ruby>読<rt>よ</rt></ruby>みに なりましたか。", "de": "Hat der Chef die Zeitung schon gelesen?"}, {"sit": "Sprich respektvoll: Der Lehrer ist gerade angekommen.", "jp": "<ruby>先生<rt>せんせい</rt></ruby>は <ruby>今<rt>いま</rt></ruby> <ruby>来<rt>こ</rt></ruby>られました。", "de": "Der Lehrer ist gerade gekommen."}]},
{"l": 49, "sit": "Sprich respektvoll via Passivform: Der Chef liest jeden Morgen Zeitung.", "more": [{"sit": "Sprich respektvoll (Passiv): Wann fahren Sie nach Hause?", "jp": "<ruby>社長<rt>しゃちょう</rt></ruby>は いつ <ruby>帰<rt>かえ</rt></ruby>られますか。", "de": "Wann fährt der Chef nach Hause?"}, {"sit": "Sprich respektvoll (Passiv): Der Chef hat das schon entschieden.", "jp": "<ruby>社長<rt>しゃちょう</rt></ruby>は もう <ruby>決<rt>き</rt></ruby>められました。", "de": "Der Chef hat schon entschieden."}]},
{"l": 49, "sit": "Bitte einen Kunden sehr höflich, einen Moment zu warten (お+Stamm+ください).", "more": [{"sit": "Bitte einen Kunden sehr höflich, hier Platz zu nehmen.", "jp": "こちらに お<ruby>座<rt>すわ</rt></ruby>り ください。", "de": "Bitte nehmen Sie hier Platz."}, {"sit": "Bitte einen Kunden, vorsichtig zu sein.", "jp": "<ruby>足元<rt>あしもと</rt></ruby>に お<ruby>気<rt>き</rt></ruby>を つけ ください。", "de": "Achten Sie bitte auf den Boden."}]},
{"l": 50, "sit": "Biete demütig an, die Tasche für jemanden zu tragen (お+Stamm+します).", "more": [{"sit": "Biete einem Kunden demütig an, das Gepäck zu tragen.", "jp": "お<ruby>荷物<rt>にもつ</rt></ruby>を お<ruby>持<rt>も</rt></ruby>ち します。", "de": "Ich trage Ihr Gepäck."}, {"sit": "Biete demütig an, einen Kunden zum Bahnhof zu fahren.", "jp": "<ruby>駅<rt>えき</rt></ruby>まで お<ruby>送<rt>おく</rt></ruby>り します。", "de": "Ich bringe Sie zum Bahnhof."}]},
{"l": 50, "sit": "Stell dich sehr höflich/demütig vor: Du heißt Miller (謙譲語).", "more": [{"sit": "Sag demütig, dass du aus Deutschland kommst.", "jp": "ドイツから <ruby>参<rt>まい</rt></ruby>りました。", "de": "Ich komme aus Deutschland."}, {"sit": "Sag demütig, dass du das schon gesehen/erhalten hast (höfl. 'sehen').", "jp": "<ruby>写真<rt>しゃしん</rt></ruby>を <ruby>拝見<rt>はいけん</rt></ruby>しました。", "de": "Ich habe das Foto gesehen."}]},
{"l": 50, "sit": "Sprich respektvoll: Der Lehrer fährt nächste Woche in die USA.", "more": [{"sit": "Sprich respektvoll: Der Chef isst gerade zu Mittag.", "jp": "<ruby>社長<rt>しゃちょう</rt></ruby>は <ruby>昼<rt>ひる</rt></ruby>ごはんを <ruby>召<rt>め</rt></ruby>し<ruby>上<rt>あ</rt></ruby>がって います。", "de": "Der Chef isst gerade zu Mittag."}, {"sit": "Sprich respektvoll: Kennen Sie Herrn Tanaka?", "jp": "<ruby>田中<rt>たなか</rt></ruby>さんを ご<ruby>存<rt>ぞん</rt></ruby>じですか。", "de": "Kennen Sie Herrn Tanaka?"}]},
{"l": 50, "sit": "Sprich respektvoll: Der Chef ist im Besprechungsraum (尊敬語).", "more": [{"sit": "Sag demütig, dass du den Chef morgen besuchst (höfl. 'gehen').", "jp": "<ruby>明日<rt>あした</rt></ruby> <ruby>社長<rt>しゃちょう</rt></ruby>の ところへ <ruby>伺<rt>うかが</rt></ruby>います。", "de": "Morgen besuche ich den Chef."}, {"sit": "Sprich respektvoll: Der Lehrer ist heute nicht da.", "jp": "<ruby>先生<rt>せんせい</rt></ruby>は <ruby>今日<rt>きょう</rt></ruby> いらっしゃいません。", "de": "Der Lehrer ist heute nicht da."}]}
